CREATE DEFINER=`root`@`localhost` FUNCTION `fn_player_age`(p_dob DATE) RETURNS int
    DETERMINISTIC
BEGIN
    IF p_dob IS NULL THEN
        RETURN NULL;
    END IF;
    RETURN TIMESTAMPDIFF(YEAR, p_dob, CURDATE());
END ;;
DELIMITER ;
